var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"쿨럭 쿨럭!","JPN":"ゲホッ、ゲホッ！","ENG":"*Cough* *Cough*","TWN":"咳咳！咳咳！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"설마... 자폭한 거야…?","JPN":"まさか……自爆したの……？","ENG":"Did she... self-destruct...?","TWN":"難道……是自爆了…？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"저, 정말 죽어버렸다고?!","JPN":"ほ、本当に死んじゃったのか！？","ENG":"S-she's really dead?!","TWN":"什麼？瑪卡死了？！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"그럴리가…!","JPN":"そんな……！","ENG":"That can't be...!","TWN":"怎麼可能…！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"침식체들이 아직 남아있다! 슬퍼하고 있을 틈이 없어!","JPN":"侵食体がまだ残っている！　悲しんでいる暇はない！","ENG":"There are still C.O.s remaining! We can mourn for her later!","TWN":"侵蝕體還在！先振作起來！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L11_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"우리들만으로 저걸 전부 토벌하는 건 불가능해!","JPN":"私たちだけであれを全部討伐するのは不可能だ！","ENG":"It's impossible for us to kill them all!","TWN":"光靠我們怎麼可能殺得死那些東西！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그렇게 무서우면 도망치면 되잖냐.","JPN":"そんに怖いなら、逃げればいいではないか。","ENG":"If you're that scared, you should run.","TWN":"害怕的話就逃跑吧！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"내가 최대한 시간을 벌어볼 테니, 어서 마을을 떠나든가 해라.","JPN":"俺ができるだけ時間稼ぎをするから、とっとと村から出るなり好きにしろ。","ENG":"I'll buy you as much time as I can, so retreat to the village or wherever you want.","TWN":"我會儘量爭取時間，你們趕快離開村子。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그게 너희들이 살 수 있는 유일한 방법이야.","JPN":"それがお前たちが生き残る唯一の方法だ。","ENG":"That's the only way you'll survive.","TWN":"這是你們唯一能活下去的方法！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"제길! 혼자서 영웅 놀이라도 하겠다는 거야 뭐야!","JPN":"くそ！　一人で英雄ごっこするつもりかよ！","ENG":"Dammit! I'm not letting you play hero by yourself!","TWN":"可惡！怎麼能讓你一個人逞英雄！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"똥폼 잡고 죽을 생각이었다면 타이밍이 다르다고!","JPN":"カッコつけといて死ぬつもりなら、タイミングが悪すぎるんだよ！","ENG":"If you were thinking of dying like one, this isn't the right time!","TWN":"就是啊！想一個人這麼死掉，也太卑鄙了！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"비참하게 죽더라도 모두 함께 죽는 거다!","JPN":"惨めに死ぬとしても、みんな一緒に死ぬんだ！","ENG":"Even if we're going to die miserably, we're in this together!","TWN":"即使要死也是一起死啊！安哥！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"퍼부을 수 있는 건 다 퍼부어!","JPN":"とにかく全て撃ちまくれ！","ENG":"Give them everything we've got!","TWN":"好！那就打起一百二十分精神來！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"침식체를 마을 밖으로 유도해야 한다!","JPN":"侵食体を村の外まではじき出さないといけない！","ENG":"Lure the C.O.s out of the village!","TWN":"必須把侵蝕體引出村外！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"마을안에서 날뛰게 해선 안 돼!","JPN":"村の中で暴れさせてはまずい！","ENG":"We mustn't let them run wild in the village!","TWN":"不能讓它們破壞我們的村子！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ff3636>바보… 꿈도 크네?</color>","JPN":"<color=#ff3636>バカ……夢がデカいね。</color>","ENG":"<color=#ff3636>Fools... How ambitious</color>.","TWN":"<color=#ff3636>愚蠢……在做夢嗎？</color>"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_SNOW"},{"id":"L26_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"순순히 마을 밖에 나가줄 리가 없잖아?","JPN":"素直に村から出てあげるわけないでしょう？","ENG":"They are not going to be lured that easily.","TWN":"你以為我會讓你們這麼做嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"네, 네년은…!","JPN":"き、貴様は……！","ENG":"Y-you are...!","TWN":"你……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"걱정하지 마. 지금은 얌전히 보고만 있을게.","JPN":"心配しないで。今は大人しく見てるだけだから。","ENG":"Don't be frightened. I'll just watch for now.","TWN":"別擔心，我會乖乖地看著的。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"당장이라도 언니들의 복수를 해주고 싶지만….","JPN":"今すぐにでも姉さんたちの復讐をしてあげたいけど……","ENG":"I would love to avenge Eva and Mavka right now, but...","TWN":"雖然我很想立刻為姊姊們報仇……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"흐~응. 그런 고물로는 내 몸에 흠집하나 낼 수 없어.","JPN":"ふーん。そんな古鉄じゃあ私の体に傷一つつけられないよ。","ENG":"Pfft. You can't even scratch me with that junk.","TWN":"哼～就憑那種破銅爛鐵，連我的身體都劃不破。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그래도 화내진 않을게. 언니들을 파괴한 당신들의 복수는….","JPN":"でも、怒らないからね。姉さんたちを破壊したあなたたちへの復讐は……","ENG":"But I won't get mad. Because those children will take revenge…","TWN":"不過我不會生氣。因為傷害姊姊們的仇……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"저 아이들이 대신해 줄 거니까.","JPN":"あの子どもたちが代わりにやってくれるから。","ENG":"for your killing my sisters.","TWN":"那些孩子們會替我報的。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L40_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"아이들이라고…?","JPN":"子どもたちだと……？","ENG":"Children...?","TWN":"孩子……？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"응. 저 아이들은 우리들이 만들어낸 침식체야.","JPN":"うん。あの子どもたちは、私たちが作り上げた侵食体だよ。","ENG":"Yup. They are C.O.s that we created.","TWN":"你看，這些孩子是我們製造的侵蝕體。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛, 저 안에는 수 많은 실험체들이 담겨있지.","JPN":"ひひっ、あの中には数多くの実験体が含まれてるの。","ENG":"Hehe. There are hundreds of test subjects inside them.","TWN":"嘻嘻，裡面裝著的可都是實驗品。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"시린그라드 사람들도 많이 섞여 있는데, 혹시 알아볼 수 있을까?","JPN":"シリングラードの人たちもたくさん混ざってるけど、もしかしてわかるかな？","ENG":"I'm sure some are even from Ciringrad. I wonder if you can recognize them.","TWN":"我確定，裡面也有錫林格勒的人，你能認得出來嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"………!!","JPN":"………！！","ENG":"...!!","TWN":"………！！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"솔직히 조금 감동했어.","JPN":"正直ちょっと感動したよ。","ENG":"I'm a little impressed.","TWN":"說實話，我有點感動。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"마브카 언니도, 당신들도… 우리에게 저항하는 모습. 경의를 표할게.","JPN":"マブカさんも、あなたたちも……私たちに抵抗する姿。尊敬する。","ENG":"You and... Mavka resisting us. I respect that.","TWN":"無論是瑪卡姊姊，還是你們……一直一直……反抗的樣子，我表示敬意。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"아~ 일이 끝나면, 이 마을에서 계속 지내고 싶다.","JPN":"あ～仕事が終わったら、この村にずっといたいなあ。","ENG":"Ah! I want to stay in this village even after my work is done here.","TWN":"啊～事情結束後，我想一直住在這個村子裡。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"어때? 이왕이면 나도 민병대로 받아줄….","JPN":"どう？　どうせなら私も民兵団に入れ……","ENG":"What do you think? Do you think I can join the militia–","TWN":"怎麼樣？既然這樣，不如也讓我加入民兵隊……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"흐음… 이 곳에 처음 왔을 때 봤던 아저씨네?","JPN":"ふーん……初めてここに来た時、見かけたおじさんだね。","ENG":"Hmm... You're the person I saw when I first arrived here.","TWN":"嗯……是我第一次來這裡時見到的那位大叔吧？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛, 그런 폭탄으론 날 해치울 수 없어.","JPN":"ひひっ、そんな爆弾では私をやっつけられないよ。","ENG":"Hehe. But a bomb like that can't kill me.","TWN":"嘿嘿，那種炸彈是傷不了我的。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"늙은이라 그런지 판단력이 많이 흐리구나?","JPN":"老いぼれだから、判断力が鈍ってるんだね？","ENG":"Guess becoming senile has blurred your judgment, huh?","TWN":"是不是因為老了，判斷力變差了呢？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"저 침식체한테 던졌다면 조금은 시간벌이라도 됐을 텐데.","JPN":"あの侵食体に投げてたら、少しくらいは時間稼ぎになったかもしれないのに。","ENG":"You could've bought some time if you threw it at those C.O.s.","TWN":"如果把它扔向那個侵蝕體，至少能爭取一點時間。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"어라…?","JPN":"あれ……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"멍청한 년. 방금 던진 건 평범한 수류탄이 아냐.","JPN":"馬鹿野郎。今投げたのは普通の手榴弾じゃない。","ENG":"Stupid girl. What I threw wasn't an ordinary grenade.","TWN":"你這個蠢女人，剛才扔的可不是普通的手榴彈。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"이터니움 분진가루를 섞은 연막탄이지.","JPN":"エタニウムの粉塵を混ぜた煙幕だ。","ENG":"It's a smoke grenade mixed with Eternium powder.","TWN":"那是混合了永恆之金粉塵的煙霧彈。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"나한테 써서 마을밖으로 유도하려 했는데, 효율적이지 못했던 건 인정하지.","JPN":"お前を村の外に引きずり出そうと思ったが、効率的でなかったことは認めよう。","ENG":"I was going to use it on me to lure the C.O.s, so I do admit that it wasn't the most effective way to use it.","TWN":"本來是想用它把侵蝕體引到村外，雖然效率不高，這點我承認。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"역시 얌전히 죽어주지 않는군.","JPN":"やはり大人しく死んではくれないな。","ENG":"As I expected. You won't go down quietly, will you?","TWN":"果然你還沒死。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"생각이 바뀌었어.","JPN":"気が変わった。","ENG":"I change my mind.","TWN":"嗯……我現在改變主意了。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"역시 아저씨는 처음 봤을 때, 죽여 버렸어야 했는데…","JPN":"やっぱりおじさんは初めて会った時に、殺すべきだったよ……","ENG":"I should've killed you when I first saw you...","TWN":"果然第一次見到你的時候，就該殺了你……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그럼 여기 아저씨 둘하고… 저기 있는 언니까지.","JPN":"じゃあ、ここのおじさん二人と……あそこのお姉さんまで。","ENG":"Then, two old guys... and the woman over there.","TWN":"那麼這裡的兩位大叔……還有那邊的姊姊。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛. 특별히 내가 직접 죽여줄게♪","JPN":"ひひっ。特別に私が直接殺してあげるね♪","ENG":"Hehe! I'll kill you myself♪","TWN":"嘿嘿，我會親自送你們上路喔♪"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"그건 내가 할 말이다. 빌어먹을 꼬맹이!","JPN":"それはこっちのセリフだ。クソガキ！","ENG":"That's my line, you brat!","TWN":"這是我要說的話吧！你這個該死的小鬼！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"여긴….","JPN":"ここは……","ENG":"Where am I...?","TWN":"這裡是……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이제야… 저승에 온 건가?","JPN":"やっと……冥府に来たのかな？","ENG":"Am I... in the afterlife?","TWN":"是……地獄嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"다 끝났구나….","JPN":"全部終わったんだ……","ENG":"So it's all over...","TWN":"終於結束了……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아얏…!","JPN":"痛っ……！","ENG":"Ow...!","TWN":"啊……！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"끝나긴 뭐가 끝나 이 바보야!","JPN":"何も終わってないよ、このバカ！","ENG":"What do you mean it's all over, stupid?!","TWN":"結束什麼啊，笨蛋！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L37_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사, 사샤…?!","JPN":"サ、サシャ……！？","ENG":"S-Sasha...?!","TWN":"莎，莎夏……？！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그래! 널 위해 이 몸께서 친히 나타나 줬다!","JPN":"そう！　あなたのために、私が自ら来てやったの！","ENG":"Yeah! I appeared just for you!","TWN":"沒錯！為了你，我親自現身！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L41_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"정말… 너야?","JPN":"本当に……あなたなの？","ENG":"Is it... really you?","TWN":"真的是……你嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"다행이다… 무사했구나…!","JPN":"よかった……無事だったんだね……！","ENG":"Thank goodness... you’re okay...!","TWN":"太好了……你沒事……！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아니, 나도 죽었어.","JPN":"ううん、私も死んだよ。","ENG":"No, I'm also dead.","TWN":"不，我也死了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L47_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"뭐, 뭐라고…?!","JPN":"な、何だって……！？","ENG":"W-what...?!","TWN":"什，什麼……？!"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"너… 이런 상황에는 내가 농담하지 말라고 몇 번이나 말했는데…!","JPN":"今みたいな状況で冗談はやめてって何度も言ったのに……！","ENG":"Hey... I told you countless times not to joke in times like this...!","TWN":"都說了多少次……不要在這種情況下開玩笑！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"도대체… 왜 마지막까지 이러는 거야…","JPN":"まったく……なんで最後までそうなの……","ENG":"Why... Why are you doing this to me until the very end...?","TWN":"到底……為什麼到最後還是這樣……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"왜!!","JPN":"なんで！！","ENG":"Just why?!","TWN":"為什麼！！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤. 그래도 기운 차린 것 같네.","JPN":"へへ。でも元気が出たみたいだね。","ENG":"Hehe. At least you seemed to have snapped out of it.","TWN":"嘿嘿，至少你振作起來了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"너도 잘 알잖아. 난 이런 사람인걸.","JPN":"あなたもよくわかってるでしょう？　私はこんな人だもん。","ENG":"You know what kind of person I am.","TWN":"你也知道的，我就是這樣的人。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"무리수였지만… 이렇게라도 농담을 던져보고 싶었어.","JPN":"ちょっと無理はあったけど……こうしてでも冗談を言ってみたかったの。","ENG":"I know it wasn't appropriate... but I still wanted to make a joke.","TWN":"雖然有點勉強……但我還是想開個玩笑。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤…….","JPN":"サシャ……","ENG":"Sasha...","TWN":"莎夏……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카, 사실 넌 죽지 않았어.","JPN":"マブカ、実はあなたは死んでないよ。","ENG":"Mavka, you're not dead yet.","TWN":"瑪卡，其實你還沒有死喔。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"기껏 살아남아놓고, 또 죽으면 서로 민망하잖아?","JPN":"せっかく生き残ったのに、また死んだらお互い気まずいじゃん？","ENG":"It'd be really embarrassing to die again after you fought for your life, right?","TWN":"好不容易活下來了，再死一次的話我們豈不是很丟臉？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그래서 마브카를 기운 차리게 해주기 위해 왔지!","JPN":"だから、マブカを元気づけるために来たってわけ！","ENG":"So I'm here to cheer you up, Mavka!","TWN":"所以我來讓瑪卡振作起來！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이걸로… 정말 마지막이 되겠지만.","JPN":"これで……本当に最後になるけど。","ENG":"Even if... this will be the last time I ever see you.","TWN":"這次……真的會是最後一次了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"마, 마지막이라고?","JPN":"さ、最後？","ENG":"Th-the last time?","TWN":"最，最後一次？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"싫어… 떠나지 마 사샤.","JPN":"嫌だ……行かないで、サシャ。","ENG":"No... Don't leave me, Sasha.","TWN":"不要……不要離開我，莎夏。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"평소처럼 장난쳐도 괜찮아… 시답잖은 농담도 이젠 다 좋으니까…!","JPN":"いつもみたいにいたずらしてもいいよ……つまらない冗談だって言ってもいいから……！","ENG":"I'll let you joke around like you always do... I won't mind your stupid joke anymore...!","TWN":"像平時那樣開玩笑也沒關係……就算是無聊的玩笑也沒關係……！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"처음부터 잘못되었던 거야.","JPN":"最初から間違ってたんだ。","ENG":"It all went wrong from the start.","TWN":"從一開始就錯了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"나 같은게 사람들을 지키겠다니… 터무니없는 꿈이었어.","JPN":"私みたいなのが人々を守るなんて……あり得ない夢だったんだ。","ENG":"Me protecting people...? What a ridiculous dream.","TWN":"像我這樣的人還想要保護別人……荒謬的想法。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"난 그냥 고아원에서 얌전히 살았어야 했다고!","JPN":"私は孤児院で大人しく暮らしているべきだったんだ！","ENG":"I should've just lived quietly in that orphanage!","TWN":"我本該老老實實待在孤兒院的！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카… 하지만 시간이 없어.","JPN":"マブカ……時間がないの。","ENG":"Mavka... But we're running out of time.","TWN":"瑪卡……但是時間不多了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"사람들이 위험해. 너 없인 모두 죽을지도 몰라.","JPN":"みんなが危ない。あなたがいないとみんな死ぬかもしれないよ。","ENG":"The village people are in danger. Without you, they might all die.","TWN":"大家很危險，沒有你，他們可能都會死。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카는 세뇌당한 상태에서도 끝까지 저항했었지?","JPN":"マブカは洗脳されてる状態でも最後まで抵抗したよね？","ENG":"You resisted them even after you were brainwashed, right?","TWN":"瑪卡，即使在被洗腦的狀態下也一直在反抗，對吧？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"자폭해서 메모리 코어를 부순 것도 마을 사람들을 위해서였잖아!","JPN":"自爆してメモリーコアを壊したのも、村の人たちのためだったじゃない！","ENG":"You even destroyed your memory core to save them!","TWN":"你自爆也是為了村民們，不是嗎！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이대로 정말 끝나도 좋은 거야?","JPN":"本当にこのまま終わってもいいの？","ENG":"Are you sure you want it to end like this?","TWN":"這樣結束真的可以嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……내가 뭘 하면 되는데?","JPN":"……私は何をすればいい？","ENG":"...What do I have to do?","TWN":"……那我該做什麼呢？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아니. 마브카는 어떻게 하길 원해?","JPN":"ううん。マブカはどうしたい？","ENG":"No. What do you want to do, Mavka?","TWN":"不，瑪卡，你想怎麼做呢？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"어…?","JPN":"え……？","ENG":"Huh...?","TWN":"唔……？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카는 정말로 나와 함께 가고 싶은 거야?","JPN":"マブカは本当に私と一緒に行きたいの？","ENG":"Mavka, do you really want to be here with me?","TWN":"瑪卡，你真的想和我一起走嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"난….","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"난… 사람들을 지키고 싶어.","JPN":"私は……みんなを守りたい。","ENG":"I... want to protect them.","TWN":"我……想保護大家。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤가 사랑했던 마을과 사람들을 지키고 싶어…!","JPN":"サシャが愛した村とみんなを守りたい……！","ENG":"I want to protect the village and the people you loved, Sasha...!","TWN":"我想保護莎夏深愛的村莊和大家……！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤를 죽인 녀석들은… 절대 용서할 수 없어!","JPN":"サシャを殺したやつらは……絶対許さない！","ENG":"The people who killed you... I'll make them pay!","TWN":"那些殺害你的傢伙……絕對不能原諒！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"반드시… 반드시 대가를 치르게 하겠어!!","JPN":"必ず……必ず代価を払わせてやる！","ENG":"No matter what... I won't forgive them!!","TWN":"一定……一定要讓他們付出代價！！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"……헤헤.","JPN":"……へへ。","ENG":"...Hehe.","TWN":"……嘿嘿。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"고마워 마브카. 그렇게 말해줘서.","JPN":"ありがとう、マブカ。そう言ってくれて。","ENG":"Thanks for saying that, Mavka.","TWN":"謝謝你，瑪卡，謝謝你這麼說。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"사실… 난 항상 너한테 미안하단 말을 해주고 싶었어.","JPN":"実は……私、いつもあなたにごめんって言いたかったの。","ENG":"Actually... I always wanted to apologize to you.","TWN":"其實……我一直想跟你說對不起。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"꼭 살아서 전해주고 싶었는데….","JPN":"生きてるうちに伝えたかったけど……","ENG":"I wanted to say this when I was alive...","TWN":"我本是想在活著的時候告訴你的……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"있잖아? 난 사실 북방군의 실험….","JPN":"あのね？　実は私、北方軍の実験……","ENG":"In truth, I was also a test subj–","TWN":"你知道嗎？其實我也是北方軍的實驗……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……말할 필요 없어.","JPN":"……話す必要はないよ。","ENG":"...You don't need to say it.","TWN":"……不需要說。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"엇, 설마 알고 있었어?!","JPN":"えっ、まさか知ってた！？","ENG":"Oh? Did you already know about it?!","TWN":"啊，難道你知道了？！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아니, 말해주지 않아도 돼.","JPN":"いや、言わなくてもいい。","ENG":"No, you just don't have to say it.","TWN":"不，你不需要說。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"다 괜찮아….","JPN":"大丈夫……","ENG":"It's fine...","TWN":"都沒事的……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"우린….","JPN":"私たちは……","ENG":"Because...","TWN":"因為我們是……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"친구…!","JPN":"友だち……！","ENG":"we're friends...!","TWN":"朋友……！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"응... 우린 친구잖아.","JPN":"うん……私たちは友だちでしょう？","ENG":"Yeah... we're friends.","TWN":"對……我們是朋友！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"……!!","JPN":"……！！","ENG":"...!!","TWN":"……！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이제… 떠나야 할 시간이겠지…?","JPN":"もう……お別れの時間だよね……？","ENG":"It's... time for you to go now, right...?","TWN":"現在……是時候離開了吧……？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그러고 보니… 난 자폭해서 파괴된 상태였는데…!","JPN":"そういえば……私は自爆して破壊された状態だったのに……！","ENG":"Come to think of it... My body's wrecked because I self-destructed...!","TWN":"這麼說來……我的身體不是自爆後被毀了嗎……！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"네 몸 어디가? 멀쩡하잖아.","JPN":"あなたの体？　どこが？　何ともないよ。","ENG":"Where? You don't look wrecked.","TWN":"你哪裡不舒服？看起來蠻好的啊。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……어?!","JPN":"……え！？","ENG":"...Huh?!","TWN":"……呃？！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤. 내가 전에 줬던 녹음기도 한번 볼래?","JPN":"へへ。私があげた録音機も見てみる？","ENG":"Hehe. Remember the recorder that I gave you?","TWN":"嘿嘿，要不要聽聽我之前給你的錄音機？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그림자 핵이… 사라졌어. 아까 자폭해서 그런 건가?!","JPN":"シャドウの核が……消えた。さっき自爆したから！？","ENG":"The Shadow Core... it's gone. Is it because of the self-destruction?!","TWN":"暗影核心……消失了。是剛才自爆的原因嗎？！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_02"},{"id":"L24_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그리고… 녹음기는 멀쩡하잖아?","JPN":"それに……録音機はそのまま。","ENG":"But... the recorder is fine...","TWN":"不過……錄音機卻完好無損？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"설마…?!","JPN":"まさか……！？","ENG":"Is this...?!","TWN":"這是……？！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응, 그건 단순한 녹음기가 아냐.","JPN":"うん、それ普通の録音機じゃないの。","ENG":"Yeah. It's not an ordinary recorder.","TWN":"嗯，那可不僅僅是個錄音機。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그건… 내 <color=#ffd34c>워치.</color> 마브카에게 줄 선물이었어.","JPN":"それは……私の<color=#ffd34c>ウォッチ。</color>マブカにあげるプレゼントだったの。","ENG":"It's... my <color=#ffd34c>Watch</color>. It's my gift to you.","TWN":"那是……我的<color=#ffd34c>能量環</color>，是要送給瑪卡的禮物。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이렇게나 능력을 잘 다루다니… 정말 다행이다.","JPN":"こんなに能力を使いこなすなんて……本当によかった。","ENG":"I can't believe how well you're able to use its ability... I'm so relieved.","TWN":"能這麼好地使用能力……真是太好了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카는 엄청 강하니까, 분명 나보다 더 잘할 수 있을 거야!","JPN":"マブカはすごく強いから、きっと私より上手くいくはずだよ！","ENG":"You're strong, Mavka. So, I'm sure you'll use it better than I did!","TWN":"瑪卡非常強大，肯定能比我做得更好！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤…!","JPN":"サシャ……！","ENG":"Sasha...!","TWN":"莎夏……！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_MAVKA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"..........","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"잘 가… 나의 친구… 마브카.","JPN":"さよなら……私の友だち……マブカ。","ENG":"Goodbye... Mavka... My friend.","TWN":"再見了……我的朋友……瑪卡。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마지막으로 진심을 담아 말할게 마브카. 너의 절친으로서.</color>","JPN":"<color=#ffd34c>最後に本心を伝えるよマブカ。あなたの親友として。</color>","ENG":"<color=#ffd34c>As your best friend, I want to speak from my heart one last time.</color>","TWN":"<color=#ffd34c>這是我最後一次，以好朋友的身分要告訴你一些話。</color>"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_SHASHA_IN_TRAILER_4"},{"id":"L39_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>난 언제나 망가진 걸 고치며 살아왔었어.</color>","JPN":"<color=#ffd34c>私はいつも壊れたものを直しながら生きてきた。</color>","ENG":"<color=#ffd34c>I've always lived by fixing broken things.</color>","TWN":"<color=#ffd34c>一直以來，我都在修復破損的東西。</color>"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_SHASHA_IN_TRAILER_5"},{"id":"L40_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>하지만, 세상에 망가지는 존재는 없더라.</color>","JPN":"<color=#ffd34c>でも、この世界で壊れる存在はないんだ。</color>","ENG":"<color=#ffd34c>But I realize that nothing in this world is broken.</color>","TWN":"<color=#ffd34c>但世上沒有什麼是真正破碎的。</color>"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_SHASHA_IN_TRAILER_6"},{"id":"L41_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>모든 것은, 더 완성되어 갈 뿐이지.</color>","JPN":"<color=#ffd34c>すべてのものは、さらに完成されていくだけだよ。</color>","ENG":"<color=#ffd34c>Everything just gets more completed.</color>","TWN":"<color=#ffd34c>一切都在不斷完善。</color>"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_SHASHA_IN_TRAILER_7"},{"id":"L42_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마브카. 난 네가 얼마나 자랑스러운지 몰라.</color>","JPN":"<color=#ffd34c>マブカ。私はあなたのことがどれほど誇らしいか。</color>","ENG":"<color=#ffd34c>You don't know how proud I am of you, Mavka.</color>","TWN":"<color=#ffd34c>瑪卡，我為你感到無比自豪。</color>"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_SHASHA_IN_TRAILER_8"},{"id":"L43_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>넌 나의 친구이자, 최고의 영웅이거든.</color>","JPN":"<color=#ffd34c>あなたは私の友達で、最高の英雄なんだから。</color>","ENG":"<color=#ffd34c>You're my friend, and the greatest hero.</color>","TWN":"<color=#ffd34c>你是我的朋友，也是我最偉大的英雄。</color>"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_SHASHA_IN_TRAILER_9"},{"id":"L44_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이제… 다시 일어서야 해.</color>","JPN":"<color=#ffd34c>また……立ち上がらなくちゃ。</color>","ENG":"<color=#ffd34c>Now... It's time to get back up on your feet.</color>","TWN":"<color=#ffd34c>現在……你必須重新站起來。</color>"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_ENERGY_ATTACK_SMALL_06","voice":"AB_UI_UNIT_VOICE_OPR_SHASHA_IN_TRAILER_10"},{"id":"L45_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>나와는 다른 진정한 영웅이 바로 너니까.</color>","JPN":"<color=#ffd34c>私とは違う真の英雄がまさにあなただから。</color>","ENG":"<color=#ffd34c>Because the real hero is you, not me.</color>","TWN":"<color=#ffd34c>因為你和我不同，你是真正的英雄。</color>"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_SHASHA_IN_TRAILER_11"},{"id":"L46_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>악당들과 맞서, 사람들을 지켜내야 할 때.</color>","JPN":"<color=#ffd34c>悪党に立ち向かって、人々を守らなければならない時。</color>","ENG":"<color=#ffd34c>You must face the villains and protect the people.</color>","TWN":"<color=#ffd34c>與惡人對抗，保護大家的時候。</color>"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_SHASHA_IN_TRAILER_12"},{"id":"L47_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그 때가 바로 지금이니까!</color>","JPN":"<color=#ffd34c>それがまさに今だから！</color>","ENG":"<color=#ffd34c>And that time is now!</color>","TWN":"<color=#ffd34c>就是現在！</color>"},"stage":{"bg":"MAVKA_02","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_ENERGY_ATTACK_BIG_11","voice":"AB_UI_UNIT_VOICE_OPR_SHASHA_IN_TRAILER_13"}]`);export{e as default};